---@class StructExecuteResult
local StructExecuteResult = LxClass("StructExecuteResult", nil)

StructExecuteResult.STATUS_INHAND = 1           --- 进行中
StructExecuteResult.STATUS_FINISH = 2           --- 已完成

StructExecuteResult.CODE_INIT = -1              --- 失败
StructExecuteResult.CODE_SUC = 0                --- 成功

StructExecuteResult.BATTLE_STATUS_ERR = 0       --- 战斗出错了
StructExecuteResult.BATTLE_STATUS_RUN = 1       --- 战斗进行中
StructExecuteResult.BATTLE_STATUS_END = 2       --- 战斗结束


function StructExecuteResult:StructExecuteResult()
    self.refId = 0

    self.state = 0

    --- 服务端下发的奖励列表
    self.rewardList = {}

    --- 通过下标的奖励列表
    self.rewardIdxList = {}

    self.moreInfos = {}

    self.code = StructExecuteResult.CODE_INIT

    self.codeInfo = ""

    self.fightReports = nil
    self.fightReportsKey = nil
end

function StructExecuteResult:CreateByPb(pb)
    --- 助手设置表refId
    self.refId = pb.refId

    --- 执行状态：1=进行中；2=已完成
    self.state = pb.state

    --- 执行获得的奖励，通用奖励格式（奖励不合并，多次结果集用|隔开。备注：一次执行结果可能有多个奖励，用[，]符号隔开）
    self:DisposeReward(pb.reward)

    --- 执行结果辅助数据（战报信息可能放这里）
    self:DisposeMoreInfos(pb.moreInfos)

    --- 结果类型，0 = 成功
    self.code = pb.code

    --- 邮件参数格式
    self:DisposeCodeInfo(pb.codeInfo)

end

function StructExecuteResult:DisposeReward(reward)
    self.rewardList = {}
    self.rewardIdxList = {}
    for i,v in ipairs(reward) do
        local itemList = {}

        local thingsDetailInfo = StructThingsDetailInfo:New()
        thingsDetailInfo:CreateByPb(v)
        local allRewardList = thingsDetailInfo:GetThingsDetailAllRewardList()
        for idx,val in ipairs(allRewardList) do
            local serverData = val.serverData

            table.insert(itemList,{
                serverData = serverData,
                index = idx,
            })

            table.insert(self.rewardList,serverData)
        end
        self.rewardIdxList[i] = itemList
    end
end

function StructExecuteResult:DisposeMoreInfos(moreInfos)
    self.moreInfos = {}
    if #moreInfos < 1 then return end
    local refId = self.refId
    local isWish = StructSettingInfo.WISH_MAP[refId] or false
    if isWish then
        --- 道具类型=道具id=倍率
        local moreInfo
        for i,v in ipairs(moreInfos) do
            v = string.split(v,",")
            moreInfo = {}
            for idx,val in ipairs(v) do
                val = string.split(val,"=")
                table.insert(moreInfo,{
                    itemType = tonumber(val[1]),
                    itemId = tonumber(val[2]),
                    rate = tonumber(val[3]),
                    idx = idx,
                })
            end
            table.insert(self.moreInfos,moreInfo)
        end
    else
        for i,v in ipairs(moreInfos) do
            table.insert(self.moreInfos,v)
        end
    end
end

function StructExecuteResult:DisposeCodeInfo(codeInfo)
    self.codeInfo = codeInfo
end

function StructExecuteResult:DisposeFightReports(pbFightReports)
    local fightReports = self.fightReports
    if not fightReports then
        fightReports = {}
        self.fightReports = fightReports
    end
    for i,v in ipairs(pbFightReports) do
        local gameHelperFightResult = StructGameHelperFightResult:New()
        gameHelperFightResult:CreateByPb(v)
        local fightReportId = gameHelperFightResult.fightReportId
        fightReports[fightReportId] = gameHelperFightResult
    end
end

-----------------------------------------------------------------

function StructExecuteResult:GetRewardList()
    return self.rewardList
end

function StructExecuteResult:GetRewardIdxList()
    return self.rewardIdxList
end

function StructExecuteResult:GetFightReports()
    return self.fightReports
end

function StructExecuteResult:GetExecuteResultData()
    return {
        refId = self.refId,
        state = self.state,
        rewardList = self.rewardList,
        rewardIdxList = self.rewardIdxList,
        moreInfos = self.moreInfos,
        code = self.code,
        codeInfo = self.codeInfo,
    }
end

function StructExecuteResult:GetBattleTypeData(battleData,battleStatus)
    local data = self:GetExecuteResultData()
    data.battleData = battleData
    data.battleStatus = battleStatus
    return data
end

function StructExecuteResult:GetExecuteResult118Data(splitTxt)
    local data = self:GetExecuteResultData()
    data.splitTxt = splitTxt
    return data
end

return StructExecuteResult